import { useState } from "react";
import base from "./pizza_base.png";

const TOPPINGS = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️", "🫑"];

const PRICES = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
  "🫑": 30,
};

const BASE_PRICE = 299;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(TOPPINGS[0]);
  const [pizza, setPizza] = useState([]);

  function handleClick(e) {
    const svg = e.currentTarget;
    const point = svg.createSVGPoint();

    point.x = e.clientX;
    point.y = e.clientY;

    // Convert screen coordinates into SVG coordinates.
    const { x, y } = point.matrixTransform(
      svg.getScreenCTM().inverse()
    );

    setPizza((pizza) => [
      ...pizza,
      {
        topping: selected,
        x,
        y,
      },
    ]);
  }

  const total =
    BASE_PRICE +
    pizza.reduce((sum, { topping }) => sum + PRICES[topping], 0);

  return (
    <main
      style={{
        textAlign: "center",
      }}
    >
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{total}</h2>

      <p>
        {TOPPINGS.map((topping) => (
          <button
            key={topping}
            disabled={selected === topping}
            onClick={() => setSelected(topping)}
          >
            {topping}
          </button>
        ))}
      </p>

      <svg
        viewBox="0 0 500 500"
        width={500}
        style={{
          maxWidth: "100%",
          height: "auto",
          cursor: "crosshair",
        }}
        onClick={handleClick}
      >
        <image
          href={base}
          x="0"
          y="0"
          width="500"
          height="500"
        />

        {pizza.map(({ topping, x, y }, index) => (
          <text
            key={index}
            x={x}
            y={y}
            fontSize="24"
            textAnchor="middle"
            dominantBaseline="middle"
            pointerEvents="none"
          >
            {topping}
          </text>
        ))}
      </svg>
    </main>
  );
}
